<script setup lang="ts">import{computed,onMounted,reactive,ref}from'vue';import{Plus,RefreshCw,Save,X}from'@lucide/vue';import{createOperatorBalance,getOperatorBalances,listOperatorResource}from'@/api/operator';import type{OperatorBalanceEntry,OperatorCustomer}from'@/types';import{useI18n}from'vue-i18n';const{t}=useI18n();const entries=ref<OperatorBalanceEntry[]>([]),customers=ref<OperatorCustomer[]>([]),modal=ref(false),error=ref('');const form=reactive({customer_id:'',kind:'allocation_increase',amount_micros:0,reference:'',note:''});const customerByID=computed(()=>Object.fromEntries(customers.value.map(v=>[v.id,v])));const money=(v=0)=>new Intl.NumberFormat(undefined,{style:'currency',currency:'USD',maximumFractionDigits:6}).format(v/1_000_000);async function load(){[entries.value,customers.value]=await Promise.all([getOperatorBalances(),listOperatorResource('customers') as Promise<OperatorCustomer[]>])}function open(){Object.assign(form,{customer_id:customers.value[0]?.id||'',kind:'allocation_increase',amount_micros:0,reference:'',note:''});modal.value=true}async function save(){try{await createOperatorBalance({...form});modal.value=false;await load()}catch(e){error.value=e instanceof Error?e.message:t('common.failed')}}onMounted(load);</script><template><main class="content crud-page"><section class="page-header"><div><h1>{{t('operatorDomain.balances')}}</h1><p>{{t('operatorDomain.balancesHelp')}}</p></div><button class="button" :disabled="!customers.length" @click="open"><Plus :size="17"/>{{t('operatorDomain.newBalance')}}</button></section><section class="table-toolbar"><button class="button secondary" @click="load"><RefreshCw :size="17"/>{{t('common.refresh')}}</button></section><div v-if="error" class="notice">{{error}}</div><section class="panel table-panel"><div class="panel-body table-scroll"><table class="data-table crud-table"><thead><tr><th>{{t('audit.time')}}</th><th>{{t('operatorDomain.customer')}}</th><th>{{t('operatorDomain.kind')}}</th><th>{{t('operatorDomain.amount')}}</th><th>{{t('operatorDomain.balanceAfter')}}</th><th>{{t('operatorDomain.reference')}}</th><th>{{t('operatorDomain.notes')}}</th></tr></thead><tbody><tr v-for="v in entries" :key="v.id"><td>{{new Date(v.created_at).toLocaleString()}}</td><td>{{customerByID[v.customer_id]?.name||v.customer_id}}</td><td><span class="pill">{{v.kind}}</span></td><td :class="v.amount_micros>=0?'status-success':'status-danger'">{{money(v.amount_micros)}}</td><td>{{money(v.balance_after_micros)}}</td><td>{{v.reference||'-'}}</td><td>{{v.note||'-'}}</td></tr><tr v-if="!entries.length"><td colspan="7" class="empty-cell"></td></tr></tbody></table></div></section><div v-if="modal" class="modal-backdrop"><form class="modal-card" @submit.prevent="save"><header class="modal-header"><h2>{{t('operatorDomain.newBalance')}}</h2><button class="icon-button" type="button" @click="modal=false"><X :size="18"/></button></header><div class="modal-body form-grid"><div class="field"><label>{{t('operatorDomain.customer')}}</label><select v-model="form.customer_id" required><option v-for="v in customers" :key="v.id" :value="v.id">{{v.name}}</option></select></div><div class="field"><label>{{t('operatorDomain.kind')}}</label><select v-model="form.kind"><option value="allocation_increase">{{t('operatorDomain.allocationIncrease')}}</option><option value="allocation_decrease">{{t('operatorDomain.allocationDecrease')}}</option><option value="cost_correction">{{t('operatorDomain.costCorrection')}}</option></select></div><div class="field"><label>{{t('operatorDomain.amount')}}</label><input v-model.number="form.amount_micros" type="number" required/></div><div class="field"><label>{{t('operatorDomain.reference')}}</label><input v-model="form.reference"/></div><div class="field field-wide"><label>{{t('operatorDomain.notes')}}</label><textarea v-model="form.note" rows="3"/></div></div><footer class="modal-footer"><button class="button secondary" type="button" @click="modal=false">{{t('common.cancel')}}</button><button class="button" type="submit"><Save :size="17"/>{{t('common.save')}}</button></footer></form></div></main></template>
